args.sparql:
SELECT DISTINCT ?city ?cityLabel
WHERE {
  ?city wdt:P31 wd:Q515 .  # instance of city
  ?city wdt:P17 wd:Q226 .  # located in India
  ?city wdt:P138 ?nickname .  # nickname property
  ?nickname rdfs:label ?nicknameLabel .
  FILTER (LANG(?nicknameLabel) = "en")
  FILTER (CONTAINS(LCASE(?nicknameLabel), "manchester"))
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
}
